// src/features/telegram/telegramRoutes.ts
var telegram = new Hono2();
telegram.post("/webhook", async (c2) => {
  const token = c2.env.OAUTH_TELEGRAM_BOT_TOKEN;
  if (!token) return c2.text("Bot Token not configured", 500);
  const secretToken = c2.req.header("X-Telegram-Bot-Api-Secret-Token");
  if (c2.env.OAUTH_TELEGRAM_WEBHOOK_SECRET && secretToken !== c2.env.OAUTH_TELEGRAM_WEBHOOK_SECRET) {
    return c2.text("Unauthorized", 403);
  }
  const update = await c2.req.json();
  if (!update.message) return c2.json({ ok: true });
  const chatId = update.message.chat.id;
  const text4 = update.message.text || "";
  if (text4.startsWith("/start")) {
    const args = text4.split(" ");
    const state = args[1];
    if (!state) {
      await sendTelegramMessage(token, chatId, "\u6B22\u8FCE\u4F7F\u7528 NodeAuth Bot\uFF01\n\u8BF7\u4ECE\u7F51\u9875\u7AEF\u53D1\u8D77\u767B\u5F55\u8BF7\u6C42\u3002");
      return c2.json({ ok: true });
    }
    let origin;
    if (c2.env.OAUTH_TELEGRAM_BOT_DOMAIN) {
      origin = `https://${c2.env.OAUTH_TELEGRAM_BOT_DOMAIN.replace(/^https?:\/\//, "")}`;
    } else {
      const url = new URL(c2.req.url);
      origin = `${url.protocol}//${url.hostname}`;
      if (!origin.startsWith("https://") && !origin.includes("localhost")) {
        origin = origin.replace("http:", "https:");
      }
    }
    const callbackUrl = `${origin}/callback/telegram?state=${state}`;
    await sendTelegramMessage(token, chatId, "\u8BF7\u70B9\u51FB\u4E0B\u65B9\u6309\u94AE\u5B8C\u6210\u767B\u5F55\u9A8C\u8BC1\uFF1A", {
      inline_keyboard: [[
        {
          text: "\u{1F510} \u786E\u8BA4\u767B\u5F55",
          login_url: { url: callbackUrl, request_write_access: true }
        }
      ]]
    });
  }
  return c2.json({ ok: true });
});
async function sendTelegramMessage(token, chatId, text4, replyMarkup) {
  const url = `https://api.telegram.org/bot${token}/sendMessage`;
  await fetch(url, {
    method: "POST",
    headers: { "Content-Type": "application/json" },
    body: JSON.stringify({
      chat_id: chatId,
      text: text4,
      reply_markup: replyMarkup
    })
  });
}
